// --- Robust JSON Parser for AI Agent Output ---

// Get the raw string from the 'output' field of the AI Agent node.
const rawOutputString = $input.first().json.output;

// 1. Initial validation of the input.
if (!rawOutputString || typeof rawOutputString !== 'string') {
  return [{ json: { error: "Input field 'output' from AI Agent is missing or not a string." } }];
}

let jsonString = null;

// --- STRATEGY 1: Find a Markdown Code Fence (Most Reliable) ---
// This regex is improved to handle 3 or more backticks (e.g., ``` or `````).
const markdownRegex = /`{3,}(?:json)?\s*([\s\S]*?)\s*`{3,}/;
const markdownMatch = rawOutputString.match(markdownRegex);

if (markdownMatch && markdownMatch[1]) {
  jsonString = markdownMatch[1].trim();
}

// --- STRATEGY 2: Fallback to Find First '{' and Last '}' (Less Reliable) ---
// This runs only if the markdown fence strategy fails. It's useful if the AI
// forgets the fence but still includes the JSON object within other text.
if (!jsonString) {
  const startIndex = rawOutputString.indexOf('{');
  const endIndex = rawOutputString.lastIndexOf('}');

  if (startIndex > -1 && endIndex > -1 && endIndex > startIndex) {
    jsonString = rawOutputString.substring(startIndex, endIndex + 1).trim();
  }
}

// 2. Check if a potential JSON string was found by either strategy.
if (!jsonString) {
  return [{ 
    json: { 
      error: "Could not find a potential JSON object using markdown or substring search.",
      originalOutput: rawOutputString
    }
  }];
}

// 3. Attempt to parse the extracted string.
try {
  const parsedJson = JSON.parse(jsonString);
  return [{ json: parsedJson }];
} catch (error) {
  // If parsing fails, it's often due to unescaped characters like newlines.
  // We'll try to fix the most common issue (unescaped newlines) and retry.
  try {
    const fixedJsonString = jsonString.replace(/\n/g, '\\n');
    const parsedJson = JSON.parse(fixedJsonString);
    return [{ json: parsedJson }];
  } catch (retryError) {
    // If it still fails, return a detailed error for debugging.
    return [{ 
      json: {
        error: "Failed to parse the JSON string, even after attempting to fix newlines.",
        stringThatFailed: jsonString,
        originalOutput: rawOutputString,
        errorMessage: retryError.message
      }
    }];
  }
}

